import{c as o,Q as r,j as n,g as t,n as a,m as i}from"./chunks/framework.rlpw0eGz.js";const l="/images/vrx-runcam.png",s="/images/vrx-runcam1.png",p="/images/vrx-runcam2.png",m="/images/vrx-runcam3.png",c="/images/vrx-runcam4.png",g="/images/vrx-runcam5.png",u="/images/vrx-runcam6.png",d="/images/vrx-runcam7.png",h="/images/vrx-runcam8.png",w=JSON.parse('{"title":"Прошивка та відновлення Runcam VRX","description":"Покрокова інструкція як прошити або відновити Runcam VRX за допомогою SD-карти та RKDevTool.","frontmatter":{"title":"Прошивка та відновлення Runcam VRX","description":"Покрокова інструкція як прошити або відновити Runcam VRX за допомогою SD-карти та RKDevTool.","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/getting-started/troubleshooting"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/getting-started/troubleshooting"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/getting-started/troubleshooting"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/getting-started/troubleshooting"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/getting-started/troubleshooting"}],["meta",{"property":"og:title","content":"Прошивка та відновлення Runcam VRX"}],["meta",{"property":"og:description","content":"Покрокова інструкція як прошити або відновити Runcam VRX за допомогою SD-карти та RKDevTool."}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-started.png"}],["meta",{"property":"og:locale","content":"uk_UA"}],["meta",{"property":"og:locale:alternate","content":"en_US"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-started.png"}],["meta",{"name":"twitter:title","content":"Прошивка та відновлення Runcam VRX"}],["meta",{"name":"twitter:description","content":"Покрокова інструкція як прошити або відновити Runcam VRX за допомогою SD-карти та RKDevTool."}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Головна\\",\\"item\\":\\"https://openfpv.com.ua/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Початок роботи\\",\\"item\\":\\"https://openfpv.com.ua/getting-started/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Прошивка та відновлення Runcam VRX\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Прошивка та відновлення Runcam VRX\\",\\"description\\":\\"Покрокова інструкція як прошити або відновити Runcam VRX за допомогою SD-карти та RKDevTool.\\",\\"inLanguage\\":\\"uk-UA\\",\\"url\\":\\"https://openfpv.com.ua/getting-started/troubleshooting\\",\\"image\\":\\"https://openfpv.com.ua/og-started.png\\",\\"dateModified\\":\\"2026-05-31T08:38:19.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"getting-started/troubleshooting.md","filePath":"getting-started/troubleshooting.md","lastUpdated":1780216699000}'),R={name:"getting-started/troubleshooting.md"};function _(f,e,v,b,x,k){return r(),n("div",null,[...e[0]||(e[0]=[t("h2",{id:"як-прошити-runcam-vrx-за-допомогою-sd-картки",tabindex:"-1"},[a("Як прошити Runcam VRX за допомогою SD картки "),t("a",{class:"header-anchor",href:"#як-прошити-runcam-vrx-за-допомогою-sd-картки","aria-label":'Permalink to "Як прошити Runcam VRX за допомогою SD картки"'},"​")],-1),t("div",{style:{}},[t("iframe",{width:"560",height:"315",src:"https://www.youtube.com/embed/jAmCpTOFpfY?si=P_2oop5EI2jQZ8eb",title:"YouTube video player",frameborder:"0",allow:"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share",referrerpolicy:"strict-origin-when-cross-origin",allowfullscreen:""})],-1),i('<p>Це коротка інструкція як прошити RunCam VRX за допомогою SD-карту.</p><p><em><strong>Крок 1:</strong></em> Завантажте файл образу прошивки - <a href="https://github.com/OpenIPC/sbc-groundstations/releases/download/zero3w-v1.9.9/radxa_1-9-9_emmc_flasher.img.xz" target="_blank">Завантажити з GitHub</a></p><p><em><strong>Крок 2:</strong></em> Запишіть образ на SD-карту</p><ul><li>Розпакуйте архів з образом.</li><li>Використовуйте програму <a href="https://sourceforge.net/projects/win32diskimager/" target="_blank">Win32 Disk Imager</a>, щоб записати образ на SD-карту.</li></ul><p><em><strong>Крок 3:</strong></em> Вставте карту памʼяті у RunCam VRX</p><ul><li>Вставте підготовлену SD-карту в слот на пристрої.</li><li>Підключіть акумулятор до VRX.</li></ul><p><em><strong>Крок 4:</strong></em> Активуйте прошивку</p><ul><li>Нахиліть <strong>один раз кнопку &quot;20/40 МГц&quot;</strong> на джойстику в праву сторону.</li></ul><p><em><strong>Крок 5:</strong></em> Завершення</p><ul><li>Дочекайтесь завершення прошивки (індикатор зупиниться або пристрій перезавантажиться).</li><li>Відʼєднайте акумулятор.</li><li>Вийміть SD-карту.</li></ul><blockquote><p>⚠️ Увага: Не вимикайте живлення під час прошивки!</p></blockquote><h2 id="як-відновити-runcam-vrx-після-невдалоі-прошивки" tabindex="-1">Як відновити Runcam VRX після невдалої прошивки <a class="header-anchor" href="#як-відновити-runcam-vrx-після-невдалоі-прошивки" aria-label="Permalink to &quot;Як відновити Runcam VRX після невдалої прошивки&quot;">​</a></h2><p>У разі, якщо внаслідок невдалої прошивки памʼять VRX (eMMC) була повністю стерта, пристрій не зможе завантажитися навіть до командного рядка. Проте не хвилюйтеся — за допомогою цієї інструкції ви легко зможете відновити або &quot;розблокувати&quot; свій VRX.</p><p><em><strong>Крок 1: Підготуйте прошивку</strong></em></p><ul><li>Переконайтесь, що у вас є правильний образ прошивки для вашого пристрою (Ruby або SBC). Це має бути звичайний образ, <strong>НЕ</strong> <code>emmc_flasher</code>.</li><li>SBC groundstation - <a href="https://github.com/OpenIPC/sbc-groundstations/releases" target="_blank"><strong>останні релізи</strong></a></li></ul><p><em><strong>Крок 2: Завантажте необхідні інструменти</strong></em></p><ul><li>Скачайте <a href="https://chipsee.com/docs/PCs/ARM/RK3568/Manuals/Software/Buildroot_Linux_Qt_5_15.html" target="_blank"><strong>RKDevTool</strong></a> та драйвер з офіційного сайту Chipsee:</li></ul><p><em><strong>Крок 3: Встановіть драйвер</strong></em></p><ul><li>Перед використанням RKDevTool встановіть драйвер для пристрою.</li></ul><p><img src="'+l+'" alt="alink" width="600px"><br></p><p><em><strong>Крок 4: Налаштування RKDevTool</strong></em></p><ol><li>Відкрийте конфігураційний файл у папці <code>RKDevTool_Release_v2.93</code>.</li><li>Змініть <code>Selected=1</code> на <code>Selected=2</code>, щоб перемкнути інтерфейс на англійську мову.</li></ol><p><img src="'+s+'" alt="alink" width="500px"><br></p><ol start="3"><li>У вікні програми клацніть правою кнопкою миші та оберіть &quot;Clear items&quot;, щоб очистити список.</li></ol><p><img src="'+p+'" alt="alink" width="600px"><br></p><p><em><strong>Крок 5: Додайте завантажувач (loader)</strong></em></p><ol><li>Переконайтесь, що ім’я файлу — <code>loader</code>.<br></li></ol><img src="'+m+'" alt="alink" width="600px"><ol start="2"><li>Завантажте <a href="https://dl.radxa.com/rock3/images/loader/rock-3a/" target="_blank"><strong>файл bin</strong></a> завантажувача з офіційного сайту Radxa.</li></ol><img src="'+c+'" alt="alink" width="600px"><ol start="3"><li>Клацніть правою кнопкою миші в програмі та оберіть &quot;Add item&quot;, щоб додати файл завантажувача.</li></ol><img src="'+g+'" alt="alink" width="600px"><p><em><strong>Крок 6: Додайте образ прошивки</strong></em></p><ol><li>Розархівуйте образ прошивки.</li><li>Вкажіть шлях до вашого образу прошивки.</li><li>Двічі клацніть по полю <code>storage</code> і оберіть <code>EMMC</code>.</li><li>Переконайтесь, що обидва пункти мають позначки, а параметр &quot;write by address&quot; активований.</li></ol><img src="'+u+'" alt="alink" width="600px"><p><em><strong>Крок 7: Переключіть VRX у режим завантажувача</strong></em></p><ol><li>Знизу пристрою, поряд з HDMI-портом, знайдіть маленьку кнопку.</li><li>Утримуйте її за допомогою голки або скрепки.</li><li>Підключіть живлення до VRX, зачекайте 2 секунди і відпустіть кнопку.</li><li>Підключіть VRX до ПК через порт USB Type-C. Програма має розпізнати пристрій.</li></ol><img src="'+d+'" alt="alink" width="600px"><p><em><strong>Крок 8: Запустіть прошивку</strong></em></p><ol><li>Натисніть кнопку &quot;Run&quot; в RKDevTool.</li><li>Дочекайтесь завершення процесу. Після успішного завершення зʼявиться повідомлення <strong>Download complete</strong>.</li></ol><img src="'+h+'" alt="alink" width="600px"><p><em><strong>Крок 9: Завершення</strong></em></p><ol><li>Вимкніть живлення та відʼєднайте VRX від ПК.</li><li>Увімкніть пристрій. VRX має завантажитись у звичайному режимі.</li></ol>',43)])])}const D=o(R,[["render",_]]);export{w as __pageData,D as default};
